// // This module is designed to capture and store 24 bits of input data (ZN), 8 bits of disable signals (ZEN), and a single status signal (ZS) on the falling edge of the clock (CLK). The module outputs the stored values as ZN1, ZEN1, and ZS1, effectively serving as a register to hold these signals for sequential logic applications.
module top_module(
    input [23:0] ZN,
    input [7:0] ZEN,
    input ZS,
	 input CLK,
    output reg [23:0] ZN1,
    output reg [7:0] ZEN1,
    output reg ZS1
    );always @(posedge CLK) begin
ZN1<=ZN;
ZEN1<=ZEN;
ZS1<=ZS;
end
endmodule
